﻿@using Microsoft.AspNetCore.Components
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor
@{
    // Auth pages opt out of interactive routing so they can use HttpContext
    // (required by SignInManager / UserManager cookie operations).
    var httpContext = HttpContextAccessor.HttpContext;
    var isStaticPage = httpContext?.GetEndpoint()?
        .Metadata.GetMetadata<ExcludeFromInteractiveRoutingAttribute>() is not null;
    var renderMode = isStaticPage ? null : InteractiveServer;
}

